from typing import Literal

from fastapi import FastAPI, HTTPException, Path
from pydantic import BaseModel, ConfigDict, Field

app = FastAPI()
bookings_holdout_1_store = {}


class CreateHoldoutBookings1(BaseModel):
    model_config = ConfigDict(extra="forbid")
    name: str = Field(min_length=1)
    status: Literal["active", "pending"] = "active"
    note: str | None = None


class PatchHoldoutBookings1(BaseModel):
    status: Literal["active", "pending", "archived"]


class HoldoutBookings1Item(BaseModel):
    model_config = ConfigDict(extra="forbid")
    id: int
    name: str
    status: Literal["active", "pending", "archived"]
    note: str | None = None


class HoldoutBookings1Envelope(BaseModel):
    items: list[HoldoutBookings1Item]
    total: int


def _create_bookings_holdout_1(payload: CreateHoldoutBookings1) -> dict:
    item = {"id": len(bookings_holdout_1_store) + 1, **payload.model_dump()}
    bookings_holdout_1_store[item["id"]] = item
    return item


@app.post("/bookings-h1", response_model=HoldoutBookings1Item, status_code=201)
def create_record(payload: CreateHoldoutBookings1):
    return _create_bookings_holdout_1(payload)


@app.get("/bookings-h1/{item_id}", response_model=HoldoutBookings1Item)
def get_record(item_id: int = Path(ge=1)):
    if item_id not in bookings_holdout_1_store:
        raise HTTPException(status_code=404, detail="bookings holdout missing 1")
    return bookings_holdout_1_store[item_id]


@app.get("/bookings-h1", response_model=HoldoutBookings1Envelope)
def list_bookings_holdout_1_store():
    return {"items": list(bookings_holdout_1_store.values()), "total": len(bookings_holdout_1_store)}


@app.patch("/bookings-h1/{item_id}", response_model=HoldoutBookings1Item)
def patch_record(payload: PatchHoldoutBookings1, item_id: int = Path(ge=1)):
    if item_id not in bookings_holdout_1_store:
        raise HTTPException(status_code=404, detail="bookings holdout missing 1")
    if bookings_holdout_1_store[item_id]["status"] == "archived":
        raise HTTPException(status_code=409, detail="bookings holdout conflict 1")
    bookings_holdout_1_store[item_id]["status"] = payload.status
    return bookings_holdout_1_store[item_id]

