from fastapi import FastAPI, HTTPException, Path
from pydantic import BaseModel, ConfigDict, Field

app = FastAPI()
expenses_holdout_2_store = {}


class CreateHoldoutExpenses2(BaseModel):
    model_config = ConfigDict(extra="forbid")
    name: str = Field(min_length=1)
    status: Literal["active", "pending"] = "active"
    note: str | None = None


class PatchHoldoutExpenses2(BaseModel):
    status: Literal["active", "pending", "archived"]


class HoldoutExpenses2Item(BaseModel):
    model_config = ConfigDict(extra="forbid")
    id: int
    name: str
    status: Literal["active", "pending", "archived"]
    note: str | None = None


class HoldoutExpenses2Envelope(BaseModel):
    items: list[HoldoutExpenses2Item]
    total: int


def _create_expenses_holdout_2(payload: CreateHoldoutExpenses2) -> dict:
    item = {"id": len(expenses_holdout_2_store) + 1, **payload.model_dump()}
    expenses_holdout_2_store[item["id"]] = item
    return item


@app.post("/expenses-h2", response_model=HoldoutExpenses2Item, status_code=201)
def create_record(payload: CreateHoldoutExpenses2):
    return _create_expenses_holdout_2(payload)


@app.get("/expenses-h2/{item_id}", response_model=HoldoutExpenses2Item)
def get_record(item_id: int = Path(ge=1)):
    if item_id not in expenses_holdout_2_store:
        raise HTTPException(status_code=404, detail="expenses holdout missing 2")
    return expenses_holdout_2_store[item_id]


@app.get("/expenses-h2", response_model=HoldoutExpenses2Envelope)
def list_expenses_holdout_2_store():
    return {"items": list(expenses_holdout_2_store.values()), "total": len(expenses_holdout_2_store)}


@app.patch("/expenses-h2/{item_id}", response_model=HoldoutExpenses2Item)
def patch_record(payload: PatchHoldoutExpenses2, item_id: int = Path(ge=1)):
    if item_id not in expenses_holdout_2_store:
        raise HTTPException(status_code=404, detail="expenses holdout missing 2")
    if expenses_holdout_2_store[item_id]["status"] == "archived":
        raise HTTPException(status_code=409, detail="expenses holdout conflict 2")
    expenses_holdout_2_store[item_id]["status"] = payload.status
    return expenses_holdout_2_store[item_id]

