    if item_id not in expenses_holdout_2_store:
        raise HTTPException(status_code=404, detail="expenses holdout missing 2")
    return expenses_holdout_2_store[item_id]


@app.get("/expenses-h2", response_model=HoldoutExpenses2Envelope)
def list_expenses_holdout_2_store():
    return {"items": list(expenses_holdout_2_store.values()), "total": len(expenses_holdout_2_store)}


@app.patch("/expenses-h2/{item_id}", response_model=HoldoutExpenses2Item)
def patch_record(payload: PatchHoldoutExpenses2, item_id: int = Path(ge=1)):
    if item_id not in expenses_holdout_2_store:
        raise HTTPException(status_code=404, detail="expenses holdout missing 2")
    if expenses_holdout_2_store[item_id]["status"] == "archived":
        raise HTTPException(status_code=409, detail="expenses holdout conflict 2")
    expenses_holdout_2_store[item_id]["status"] = payload.status
    return expenses_holdout_2_store[item_id]
